const body = $json.body || $json;
const envelope = body.payload || body;
const payload = envelope.payload || envelope;
const action = payload.action || payload;
const tool = payload.tool || {};
const capability = action.capability || tool.capability || payload.capability || 'log.event';
const actionPayload = action.payload || payload.payload || {};
const scene = String(actionPayload.scene || payload.scene || '').trim();
const isObsSwitch = capability === 'obs.switch_scene';
const isObsList = capability === 'obs.list_scenes';
return [{
  json: {
    product: body.product || payload.product || 'Odessa',
    capability,
    route: isObsSwitch || isObsList ? 'obs' : 'simulated',
    operation: isObsSwitch ? 'setCurrent' : 'list',
    scene,
    action,
    tool,
    decision: payload.decision || {},
    receivedAt: new Date().toISOString()
  }
}];

const original = $('Normalize Action').first().json;
const obs = $json;
const rawScenes = obs.scenes || obs.sceneList || obs.data?.scenes || [];
const scenes = Array.isArray(rawScenes)
  ? rawScenes.map((scene) => typeof scene === 'string' ? scene : (scene.sceneName || scene.name || '')).filter(Boolean)
  : [];
const currentScene = obs.currentScene || obs.currentSceneName || obs.currentProgramSceneName || original.scene || null;
const executed = original.capability === 'obs.switch_scene';
return [{
  json: {
    ok: true,
    executed,
    simulated: false,
    capability: original.capability,
    scene: original.scene || currentScene,
    currentScene,
    scenes,
    message: executed
      ? `OBS trocou para ${currentScene || original.scene}`
      : `OBS retornou ${scenes.length} cena(s)`,
    obsResponse: obs,
    receivedAt: original.receivedAt,
    completedAt: new Date().toISOString()
  }
}];

const routes = {
  'media.play_music': 'Media music adapter placeholder',
  'media.play_video': 'Media video adapter placeholder',
  'chat.reply': 'Chat reply adapter placeholder',
  'moderation.message': 'Moderation adapter placeholder',
  'obs.show_overlay': 'Overlay adapter placeholder',
  'gift.acknowledge': 'Gift acknowledge log',
  'topic.suggest': 'Topic suggestion log',
  'topic.set': 'Topic state log',
  'memory.remember': 'Memory log',
  'log.event': 'Local log'
};
return [{
  json: {
    ok: true,
    executed: false,
    simulated: true,
    capability: $json.capability,
    adapter: routes[$json.capability] || 'Generic adapter placeholder',
    message: `Action audited in n8n: ${$json.capability}`,
    action: $json.action,
    receivedAt: $json.receivedAt,
    completedAt: new Date().toISOString()
  }
}];
